import React from "react";
import "./ModernSeriesCard.css";

export interface ModernSeriesCardProps {
  id: string;
  title: string;
  sermonCount: number;
  description?: string;
  onClick?: () => void;
}

/**
 * ModernSeriesCard - A clean, minimal series card without images
 * Displays sermon series information with text-first design
 */
const ModernSeriesCard: React.FC<ModernSeriesCardProps> = ({
  id,
  title,
  sermonCount,
  description,
  onClick,
}) => {
  return (
    <div className="modern-series-card" onClick={onClick}>
      <div className="modern-series-card__content">
        {/* Series count badge */}
        <div className="modern-series-card__count">
          {sermonCount} {sermonCount === 1 ? "Sermon" : "Sermons"}
        </div>

        {/* Title */}
        <h3 className="modern-series-card__title">{title}</h3>

        {/* Description if available */}
        {description && (
          <p className="modern-series-card__description">{description}</p>
        )}

        {/* View link */}
        <div className="modern-series-card__action">
          View Series →
        </div>
      </div>
    </div>
  );
};

export default ModernSeriesCard;

