import React, { useState, useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import ModernSeriesCard from "../components/ModernSeriesCard";
import Pagination from "../components/Pagination";
import LoadingSpinner from "../components/LoadingSpinner";
import PageContainer from "../components/PageContainer";
import { sermonsAPI, Sermon } from "../services/api";
import "./Sermon.css";

interface SermonSeries {
  id: string;
  title: string;
  sermonCount: number;
  description?: string;
}

const SermonPage: React.FC = () => {
  const navigate = useNavigate();
  const [currentPage, setCurrentPage] = useState(1);
  const [sermonSeries, setSermonSeries] = useState<SermonSeries[]>([]);
  const [filteredSeries, setFilteredSeries] = useState<SermonSeries[]>([]);
  const [searchQuery, setSearchQuery] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const itemsPerPage = 9; // Show 9 series per page

  const loadSermons = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const sermons = await sermonsAPI.getAll({
        status: "PUBLISHED",
        isPublic: "true",
      });

      // Group sermons by series
      const seriesMap = new Map<string, Sermon[]>();
      sermons.forEach((sermon) => {
        const seriesName = sermon.series || "Standalone Sermons";
        if (!seriesMap.has(seriesName)) {
          seriesMap.set(seriesName, []);
        }
        seriesMap.get(seriesName)!.push(sermon);
      });

      // Convert to series array
      const seriesArray: SermonSeries[] = Array.from(seriesMap.entries()).map(
        ([seriesName, seriesSermons]) => {
          // Create a clean ID from series name
          const seriesId =
            seriesName === "Standalone Sermons"
              ? "standalone-sermons"
              : seriesName
                  .toLowerCase()
                  .replace(/\s+/g, "-")
                  .replace(/[^a-z0-9-]/g, "");
          return {
            id: seriesId,
            title: seriesName,
            sermonCount: seriesSermons.length,
          };
        }
      );

      // Sort by sermon count (most sermons first)
      seriesArray.sort((a, b) => b.sermonCount - a.sermonCount);

      setSermonSeries(seriesArray);
      setFilteredSeries(seriesArray);
    } catch (err: any) {
      console.error("Error loading sermons:", err);
      setError(err.message || "Failed to load sermons");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadSermons();
  }, [loadSermons]);

  // Filter series based on search query
  useEffect(() => {
    if (!searchQuery.trim()) {
      setFilteredSeries(sermonSeries);
    } else {
      const filtered = sermonSeries.filter((series) =>
        series.title.toLowerCase().includes(searchQuery.toLowerCase())
      );
      setFilteredSeries(filtered);
    }
    setCurrentPage(1); // Reset to first page when filtering
  }, [searchQuery, sermonSeries]);

  // Calculate pagination
  const totalPages = Math.ceil(filteredSeries.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const paginatedSeries = filteredSeries.slice(startIndex, endIndex);

  const handleSeriesClick = (seriesId: string) => {
    navigate(`/sermon/${seriesId}`);
  };

  const handlePageChange = (page: number) => {
    setCurrentPage(page);
    window.scrollTo({
      top: 0,
      behavior: "smooth",
    });
  };

  if (loading) {
    return (
      <PageContainer>
        <div className="sermon-page">
          <div className="sermon-page__header">
            <h1 className="sermon-page__title">Sermon Series</h1>
            <p className="sermon-page__subtitle">
              Explore God's word through our sermon series
            </p>
          </div>
          <div style={{ padding: "4rem", textAlign: "center" }}>
            <LoadingSpinner message="Loading sermon series..." />
          </div>
        </div>
      </PageContainer>
    );
  }

  if (error) {
    return (
      <PageContainer>
        <div className="sermon-page">
          <div className="sermon-page__header">
            <h1 className="sermon-page__title">Sermon Series</h1>
            <p className="sermon-page__subtitle">
              Explore God's word through our sermon series
            </p>
          </div>
          <div className="sermon-page__error">
            <p>Unable to load sermons. Please try again.</p>
            <button
              onClick={loadSermons}
              className="sermon-page__retry-button"
            >
              Retry
            </button>
          </div>
        </div>
      </PageContainer>
    );
  }

  return (
    <PageContainer>
      <div className="sermon-page">
        {/* Page Header */}
        <div className="sermon-page__header">
          <h1 className="sermon-page__title">Sermon Series</h1>
          <p className="sermon-page__subtitle">
            Explore our collection of {sermonSeries.length} sermon series
          </p>
        </div>

        {/* Search Bar */}
        {sermonSeries.length > 0 && (
          <div className="sermon-page__search">
            <input
              type="text"
              className="sermon-page__search-input"
              placeholder="Search sermon series..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              aria-label="Search sermon series"
            />
            {searchQuery && (
              <button
                className="sermon-page__search-clear"
                onClick={() => setSearchQuery("")}
                aria-label="Clear search"
              >
                Clear
              </button>
            )}
          </div>
        )}

        {/* Empty State */}
        {filteredSeries.length === 0 && (
          <div className="sermon-page__empty">
            <p>No sermon series match your search.</p>
            <button
              className="sermon-page__clear-button"
              onClick={() => setSearchQuery("")}
            >
              Clear Search
            </button>
          </div>
        )}

        {/* Series Grid */}
        {filteredSeries.length > 0 && (
          <>
            <div className="sermon-page__grid">
              {paginatedSeries.map((series) => (
                <ModernSeriesCard
                  key={series.id}
                  id={series.id}
                  title={series.title}
                  sermonCount={series.sermonCount}
                  description={series.description}
                  onClick={() => handleSeriesClick(series.id)}
                />
              ))}
            </div>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="sermon-page__pagination">
                <Pagination
                  currentPage={currentPage}
                  totalPages={totalPages}
                  onPageChange={handlePageChange}
                  showFirstLast={true}
                  maxVisiblePages={5}
                />
              </div>
            )}
          </>
        )}
      </div>
    </PageContainer>
  );
};

export default SermonPage;
